void processOrder(Order order) {
    // validate
    if (order.getItems().isEmpty()) throw new IllegalArgumentException("Order has no items");
    if (order.getCustomer() == null) throw new IllegalArgumentException("Order has no customer");
    // calculate pricing
    double subtotal = 0;
    for (OrderLine line : order.getLines()) {
        subtotal += line.getQuantity() * line.getUnitPrice();
    }
    double tax = subtotal * 0.08;
    order.setTotal(subtotal + tax);
    // reserve inventory
    for (OrderLine line : order.getLines()) {
        inventoryService.reserve(line.getProductId(), line.getQuantity());
    }
    // notify
    emailService.sendOrderConfirmation(order.getCustomer().getEmail(), order.getId());
}
